// Код для подготовки данных после Merge
const allItems = $input.all();

console.log('=== ДЕБАГ: Начало обработки ===');
console.log('Получено элементов:', allItems.length);

// Логируем структуру первого элемента
if (allItems.length > 0) {
  console.log('Структура первого элемента:', JSON.stringify(allItems[0], null, 2));
}

// Если нет данных
if (!allItems || allItems.length === 0) {
  console.log('Нет входных данных!');
  return [{
    json: {
      error: "Нет данных для обработки",
      status: "empty",
      timestamp: new Date().toISOString()
    }
  }];
}

// Обрабатываем только валидные элементы
const validItems = allItems.filter(item => {
  const json = item.json;
  return json && json.title && json.link;
});

console.log('Валидных элементов:', validItems.length);

if (validItems.length === 0) {
  return [{
    json: {
      error: "Нет валидных постов (отсутствуют title или link)",
      status: "invalid",
      raw_data: allItems.map(item => item.json)
    }
  }];
}

// Группируем по каналам
const groupedByChannel = {};

validItems.forEach(item => {
  const json = item.json;
  const channel = json.channel || 'Без категории';

  if (!groupedByChannel[channel]) {
    groupedByChannel[channel] = [];
  }

  groupedByChannel[channel].push({
    title: json.title,
    content: json.content || json.description || '',
    link: json.link,
    date: json.pubDate || json.isoDate
  });
});

// Формируем данные для AI
const channels = Object.keys(groupedByChannel).map(channel => ({
  channel_name: channel,
  posts: groupedByChannel[channel],
  post_count: groupedByChannel[channel].length
}));

// Создаем текстовое представление для промта
let aiPromptText = "СОЗДАЙ ДАЙДЖЕСТ НОВОСТЕЙ:\n\n";
channels.forEach(channel => {
  aiPromptText += `--- КАНАЛ: ${channel.channel_name} (${channel.post_count} постов) ---\n`;
  channel.posts.forEach((post, index) => {
    aiPromptText += `ПОСТ ${index + 1}:\n`;
    aiPromptText += `Заголовок: ${post.title}\n`;
    aiPromptText += `Содержание: ${post.content.substring(0, 300)}${post.content.length > 300 ? '...' : ''}\n`;
    aiPromptText += `Ссылка: ${post.link}\n\n`;
  });
});

console.log('Сформирован AI промт, длина:', aiPromptText.length);

return [{
  json: {
    channels: channels,
    ai_prompt: aiPromptText,
    total_posts: validItems.length,
    total_channels: channels.length,
    status: "ready_for_ai"
  }
}];

// Просто передаем данные в AI Agent
const input = $input.first();

console.log('Данные для AI Agent:', input?.json?.status);

// Проверяем, есть ли данные для обработки
if (!input || input.json.status === "empty" || input.json.status === "invalid") {
  // Если нет данных, отправляем сообщение в Telegram
  return [{
    json: {
      telegram_message: "📭 Сегодня нет новых постов для дайджеста.",
      skip_ai: true
    }
  }];
}

// Если данные есть, передаем их в AI
return $input.all();
